// ════════════════════════════════════════
// CHART HELPERS
// ════════════════════════════════════════
function barChart(vals, color, h=60){
  const max=Math.max(...vals), w=260, n=vals.length, bw=Math.floor((w-(n-1)*3)/n);
  return `<svg viewBox="0 0 ${w} ${h}" style="width:100%;height:${h}px">${vals.map((v,i)=>{
    const bh=Math.round((v/max)*h);
    return `<rect x="${i*(bw+3)}" y="${h-bh}" width="${bw}" height="${bh}" rx="3" fill="${color}" opacity="${0.35+0.65*(v/max)}"/>`;
  }).join('')}</svg>`;
}
function lineChart(vals, color, h=60){
  const max=Math.max(...vals), min=Math.min(...vals), n=vals.length, w=260;
  const pts=vals.map((v,i)=>`${Math.round(i*(w/(n-1)))},${Math.round(h-(v-min)/(max-min||1)*h*0.8-h*0.1)}`).join(' ');
  const id='lg'+Math.random().toString(36).slice(2,6);
  const area=`M${pts.split(' ')[0]} L${pts.split(' ').join(' L')} L${w},${h} L0,${h} Z`;
  return `<svg viewBox="0 0 ${w} ${h}" style="width:100%;height:${h}px"><defs><linearGradient id="${id}" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stop-color="${color}" stop-opacity="0.18"/><stop offset="100%" stop-color="${color}" stop-opacity="0"/></linearGradient></defs><path d="${area}" fill="url(#${id})"/><polyline points="${pts}" fill="none" stroke="${color}" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"/></svg>`;
}
function nav(title, links, active, c, l){
  return ""; // Removed inner top nav to prevent duplication with global layout
}
function sb(items, active, c, l){
  return ""; // Removed inner sidebar to prevent duplication with global layout
}
function stats(arr){
  return `<div class="s-stat-grid">${arr.map(([lbl,val,chg,up])=>`<div class="s-stat"><div class="s-stat-lbl">${lbl}</div><div class="s-stat-val">${val}</div>${chg?`<div class="s-stat-chg ${up?'up':'dn'}">${chg}</div>`:''}</div>`).join('')}</div>`;
}
function badge(txt, type){ return `<span class="s-badge ${type}">${txt}</span>`; }
function tgl(name, desc, on){
  return `<div class="s-toggle"><div><div class="s-toggle-name">${name}</div><div class="s-toggle-desc">${desc}</div></div><div class="s-switch ${on?'on':'off'}"><div class="s-switch-knob"></div></div></div>`;
}
function settingsScreen(n2, sb2, sNav, toggleItems, c){
  return `<div class="screen" style="--screen-c:${c}">${n2}<div class="s-page">${sb2}<div class="s-main">
    <div style="font-size:16px;font-weight:800;color:var(--text);margin-bottom:16px">Settings</div>
    <div style="display:grid;grid-template-columns:180px 1fr;gap:16px">
      <div style="display:flex;flex-direction:column;gap:2px">${sNav.map((it,i)=>`<div style="padding:8px 10px;border-radius:var(--r-lg);font-size:12px;cursor:pointer;font-weight:${i===0?700:500};${i===0?`background:var(--screen-light);color:${c}`:'color:var(--text-3)'}">${it}</div>`).join('')}</div>
      <div class="s-info-card"><div class="s-info-card-title">Preferences</div>${toggleItems.map(([n3,d,on])=>tgl(n3,d,on)).join('')}</div>
    </div>
  </div></div></div>`;
}

