// ── State ──
let mktCurrentTemplate = null;
let mktCurrentScreen = 0;

// ── Entry point: called by "Use Template" buttons ──
function openMktWorkspace(templateName) {
  mktCurrentTemplate = templateName;
  mktCurrentScreen = 0;
  const wsPage = document.getElementById('workspace-page');
  const launcher = document.getElementById('demo-launcher');
  if (wsPage) { wsPage.style.display = 'flex'; wsPage.style.flexDirection = 'column'; }
  if (launcher) launcher.style.display = 'none';
  mktBuildSidebar();
  mktRenderScreen(0);
}

// ── Connect this to college_hunt.html ──
// In college_hunt.html, the openWorkspace() function handles WORKSPACE_TEMPLATES.
// Extend it by adding these names to WORKSPACE_TEMPLATES array and calling
// openMktWorkspace() when the name matches a MKT_SCREENS key.

function closeMktWorkspace() {
  const wsPage = document.getElementById('workspace-page');
  const launcher = document.getElementById('demo-launcher');
  if (wsPage) wsPage.style.display = 'none';
  if (launcher) launcher.style.display = 'flex';
  // In college_hunt.html: call closeWorkspace() instead
}

function mktBuildSidebar() {
  const list = document.getElementById('mkt-screens-list');
  if (!list) return;
  const screens = MKT_SCREENS[mktCurrentTemplate] || [];
  const c = MKT_COLORS[mktCurrentTemplate] || '#635BFF';
  list.innerHTML = screens.map((s, i) => `
    <div class="ws-nav-item${i === mktCurrentScreen ? ' ws-active' : ''}" onclick="mktNavClick(this,${i})" id="mkt-nav-${i}">
      <svg viewBox="0 0 24 24"><path d="${s.icon}"/></svg>
      ${s.name}
      ${i === 0 ? `<span class="ws-nav-dot" style="background:${c}"></span>` : ''}
    </div>
  `).join('');
}

function mktNavClick(el, index) {
  mktCurrentScreen = index;
  document.querySelectorAll('.ws-nav-item').forEach(n => n.classList.remove('ws-active'));
  el.classList.add('ws-active');
  mktRenderScreen(index);
}

// ── Screen renderers ──
function mktRenderScreen(index) {
  const area = document.getElementById('mkt-content-area');
  if (!area) return;
  const screens = MKT_SCREENS[mktCurrentTemplate];
  const c = MKT_COLORS[mktCurrentTemplate] || '#635BFF';
  const screenName = screens[index]?.name || 'Dashboard';
  const topbarScreen = document.getElementById('mkt-topbar-screen');
  if (topbarScreen) topbarScreen.textContent = screenName;

  // Dispatch to template-specific renderer
  const renderers = {
    'Sales Pipeline CRM':   mktRenderCRM,
    'KPI Dashboard':        mktRenderKPI,
    'Admin Panel':          mktRenderAdmin,
    'Order Tracking System':mktRenderOrders,
    'Job Marketplace':      mktRenderJobs,
    'Sprint Planner':       mktRenderSprint,
    'Notes Workspace':      mktRenderNotes,
    'Employee Dashboard':   mktRenderEmployee,
    'Freelancer Platform':  mktRenderFreelancer,
    'Booking Platform':     mktRenderBooking,
  };

  const render = renderers[mktCurrentTemplate];
  if (render) {
    area.innerHTML = render(index, screenName, c);
  } else {
    area.innerHTML = mktGenericScreen(index, screenName, c);
  }
}

// ─────────────────────────────────────────
// Helper: KPI card
function mktKpi(label, val, c, bg, trend, sub) {
  return `<div class="ws-kpi" style="border-color:${c}22">
    <div class="ws-kpi-label">${label}</div>
    <div class="ws-kpi-val" style="color:${c}">${val}</div>
    <div class="ws-kpi-trend" style="color:${trend==='up'?'#00A37A':'#E5484D'};font-size:12px;font-weight:600;margin-top:3px">${trend==='up'?'↑':'↓'} ${sub}</div>
  </div>`;
}
// Helper: section header
function mktHeader(title, sub, c, btnLabel) {
  return `<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:20px">
    <div><div style="font-size:20px;font-weight:800;color:var(--text);letter-spacing:-0.4px">${title}</div>
    <div style="font-size:13px;color:var(--text-3);margin-top:3px">${sub}</div></div>
    ${btnLabel?`<button style="padding:8px 16px;background:${c};color:#fff;border:none;border-radius:9px;font-size:13px;font-weight:600;cursor:pointer;font-family:var(--font)">+ ${btnLabel}</button>`:''}
  </div>`;
}
// Helper: table
function mktTableHead(...cols) {
  return `<thead><tr>${cols.map(c=>`<th>${c}</th>`).join('')}</tr></thead>`;
}
// Helper: status badge
function mktBadge(text, color, bg) {
  return `<span class="ws-badge" style="background:${bg};color:${color}">${text}</span>`;
}

// ─────────────────────────────────────────
// COMPREHENSIVE SHARED HELPERS
// ─────────────────────────────────────────
function mktKpiRow(kpis){
  return `<div style="display:grid;grid-template-columns:repeat(4,1fr);gap:13px;margin-bottom:18px">${kpis.join('')}</div>`;
}
function mktRow(items){
  return `<div style="display:grid;grid-template-columns:${items.map(()=>'1fr').join(' ')};gap:14px">${items.join('')}</div>`;
}
function mktCard(html,extra=''){
  return `<div style="background:#fff;border:1.5px solid var(--border);border-radius:14px;padding:18px 20px;${extra}">${html}</div>`;
}
function mktCardTitle(t){
  return `<div style="font-size:13.5px;font-weight:700;color:var(--text);margin-bottom:14px">${t}</div>`;
}
function mktBar(data,c){
  const mx=Math.max(...data.map(d=>d[1]));
  return `<div style="display:flex;align-items:flex-end;gap:6px;height:90px">${data.map(([l,v],i)=>`
    <div style="flex:1;display:flex;flex-direction:column;align-items:center;gap:4px">
      <div style="width:100%;height:${Math.round((v/mx)*100)}%;background:${i>=data.length-2?c:c+'44'};border-radius:4px 4px 0 0;min-height:4px"></div>
      <div style="font-size:9.5px;color:var(--text-4)">${l}</div>
    </div>`).join('')}</div>`;
}
function mktProg(pct,c,label=''){
  return `<div style="margin-bottom:10px">${label?`<div style="display:flex;justify-content:space-between;margin-bottom:4px"><span style="font-size:12.5px;font-weight:600;color:var(--text)">${label}</span><span style="font-size:12px;color:${c};font-weight:700">${pct}%</span></div>`:''}
  <div style="height:6px;background:var(--border);border-radius:3px"><div style="height:100%;width:${pct}%;background:${c};border-radius:3px"></div></div></div>`;
}
function mktStep(steps,cur,c){
  return `<div style="display:flex;align-items:center;justify-content:space-between;position:relative;padding:0 8px">
    <div style="position:absolute;top:13px;left:8px;right:8px;height:2px;background:var(--border)"><div style="height:100%;width:${Math.round((cur/(steps.length-1))*100)}%;background:${c}"></div></div>
    ${steps.map((s,i)=>`<div style="display:flex;flex-direction:column;align-items:center;gap:6px;z-index:1">
      <div style="width:26px;height:26px;border-radius:50%;border:2.5px solid ${i<=cur?c:'var(--border)'};background:${i<cur?c:i===cur?c:'#fff'};display:flex;align-items:center;justify-content:center">
        ${i<cur?`<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="white" stroke-width="3" stroke-linecap="round"><polyline points="20 6 9 17 4 12"/></svg>`:i===cur?`<div style="width:7px;height:7px;border-radius:50%;background:#fff"></div>`:''}
      </div>
      <div style="font-size:9.5px;text-align:center;max-width:60px;font-weight:${i<=cur?700:400};color:${i<=cur?c:'var(--text-4)'}">${s}</div>
    </div>`).join('')}
  </div>`;
}
function mktListRow(icon,title,sub,right=''){
  return `<div style="display:flex;align-items:center;gap:10px;padding:8px 0;border-bottom:1px solid var(--border-2)">
    <div style="width:30px;height:30px;border-radius:9px;background:${icon.bg||'var(--lilac)'};display:flex;align-items:center;justify-content:center;font-size:${icon.emoji?'16':'11'}px;font-weight:700;color:${icon.color||'var(--indigo)'};flex-shrink:0">${icon.emoji||icon.initials||'?'}</div>
    <div style="flex:1"><div style="font-size:13px;font-weight:600;color:var(--text)">${title}</div>${sub?`<div style="font-size:11px;color:var(--text-4);margin-top:1px">${sub}</div>`:''}</div>
    ${right}
  </div>`;
}
function mktTog(on,c){
  return `<div style="width:40px;height:22px;border-radius:11px;background:${on?c:'var(--border)'};cursor:pointer;position:relative;flex-shrink:0"><div style="position:absolute;top:3px;${on?'left:21px':'left:3px'};width:16px;height:16px;border-radius:50%;background:#fff;transition:left 0.2s"></div></div>`;
}
function mktSettingsScreen(c){
  return mktHeader('Settings','System preferences & configuration',c,'')
  +`<div style="display:grid;grid-template-columns:repeat(2,1fr);gap:14px">${[['🎨 Theme','Light / Dark / Auto'],['🔔 Notifications','Email, Push, Digest'],['🔐 Privacy','Data sharing settings'],['⌨️ Keyboard','Custom shortcuts'],['💾 Storage','Backup & restore'],['👥 Team','Invite & permissions']].map(([t,d])=>`
  <div style="border:1.5px solid var(--border);border-radius:14px;padding:16px;cursor:pointer" onmouseover="this.style.borderColor='${c}'" onmouseout="this.style.borderColor='var(--border)'">
    <div style="font-size:15px;font-weight:700;color:var(--text);margin-bottom:4px">${t}</div>
    <div style="font-size:12px;color:var(--text-4)">${d}</div>
  </div>`).join('')}</div>`;
}

