let currentTemplateName = '';

function buildScreensSidebar(templateName) {
  const screens = TEMPLATE_SCREENS[templateName] || DEFAULT_SCREENS;
  const list = document.getElementById('ws-screens-list');
  list.innerHTML = screens.map((s,i) => `
    <div class="ws-nav-item ${i===0?'ws-active':''}" onclick="switchScreen(${i},'${s.name}',this)" style="gap:9px">
      <svg viewBox="0 0 24 24" style="width:15px;height:15px;flex-shrink:0;stroke:currentColor;fill:none;stroke-width:1.8;stroke-linecap:round"><path d="${s.icon}"/></svg>
      ${s.name}
    </div>
  `).join('');
}

// Navbar
function toggleNav(name, event) {
  if(event) event.stopPropagation();
  const ni = document.getElementById('ni-'+name);
  const isOpen = ni.classList.contains('open');
  document.querySelectorAll('.nav-item.open').forEach(el => el.classList.remove('open'));
  if(!isOpen) ni.classList.add('open');
}
document.addEventListener('click', e => { if(!e.target.closest('.nav-item')) document.querySelectorAll('.nav-item.open').forEach(el => el.classList.remove('open')); });
document.addEventListener('keydown', e => { if(e.key==='Escape') document.querySelectorAll('.nav-item.open').forEach(el => el.classList.remove('open')); });

function filterTab(el) {
  document.querySelectorAll('.ftab').forEach(t => t.classList.remove('active'));
  el.classList.add('active');
}
function selectCat(el) {
  document.querySelectorAll('.cat-card').forEach(c => c.classList.remove('active'));
  el.classList.add('active');
}
let catsOpen = false;
function toggleCats() {
  catsOpen = !catsOpen;
  document.querySelectorAll('.extra-cats').forEach(el => el.classList.toggle('visible', catsOpen));
  const btn = document.getElementById('show-more-btn');
  btn.innerHTML = catsOpen
    ? '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round"><line x1="5" y1="12" x2="19" y2="12"/></svg> Show less'
    : '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round"><line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/></svg> Show more categories';
}

let savedScrollY = 0;
function openWorkspace(name, meta) {
  savedScrollY = window.scrollY;
  const templateId = slugify(name);
  history.pushState({page:'workspace',templateId},'','/workspace/'+templateId);
  _showWorkspace(name, meta);
  // Load isolated chat session for this template
  setTimeout(() => loadChatSession(name), 800);
}
function _showWorkspace(name, meta) {
  currentTemplateName = name;
  const ws = document.getElementById('workspace-page');
  ws.classList.toggle('saas-mode', name === 'SaaS Analytics Dashboard');
  ws.classList.add('visible');
  document.body.style.overflow = 'hidden';
  document.getElementById('ws-app-title').textContent = name;
  const firstScreen = (TEMPLATE_SCREENS[name] || DEFAULT_SCREENS)[0];
  const screenLabel = document.getElementById('ws-screen-label');
  if(screenLabel) screenLabel.textContent = firstScreen ? firstScreen.name : 'Dashboard';
  buildScreensSidebar(name);
  // Show/hide AI-only topbar buttons (GitHub + Add Connection) for AI Support Agent & AI Chatbot
  const isAITemplate = (name === 'AI Support Agent' || name === 'AI Chatbot');
  document.querySelectorAll('.ws-ai-only').forEach(function(el){ el.style.display = isAITemplate ? '' : 'none'; });
  // Update Manager/Share button depending on template type
  var managerBtn = document.getElementById('ws-btn-manager');
  if(managerBtn) {
    managerBtn.innerHTML = '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" style="width:14px;height:14px;margin-right:5px"><rect x="3" y="3" width="7" height="7" rx="1"/><rect x="14" y="3" width="7" height="7" rx="1"/><rect x="3" y="14" width="7" height="7" rx="1"/><rect x="14" y="14" width="7" height="7" rx="1"/></svg>Managing';
  }
  const loading = document.getElementById('ws-loading');
  const appContent = document.getElementById('ws-app-content');
  loading.style.display = 'flex';
  appContent.style.display = 'none';
  const steps = ['Creating Workspace...','Loading screens...','Preparing components...','Applying theme...','Almost ready...'];
  const fill = document.getElementById('ws-progress-fill');
  const stepEl = document.getElementById('ws-loading-step');
  let i = 0;
  fill.style.width = '0%';
  const interval = setInterval(() => {
    if(i >= steps.length) {
      clearInterval(interval);
      fill.style.width = '100%';
      setTimeout(() => {
        loading.style.display = 'none';
        renderAppContent(name);
        appContent.style.display = 'flex';
        appContent.classList.add('visible');
        document.querySelectorAll('.ws-screen-item').forEach((el,idx) => el.classList.toggle('active', idx===0));
        // Activate first sidebar screen item
        const firstSidebarItem = document.querySelector('#ws-screens-list .ws-nav-item');
        if(firstSidebarItem) firstSidebarItem.classList.add('ws-active');
      }, 400);
      return;
    }
    stepEl.textContent = steps[i];
    fill.style.width = ((i+1)/steps.length*90)+'%';
    i++;
  }, 500);
}
function closeWorkspace() {
  const ws = document.getElementById('workspace-page');
  ws.classList.remove('visible', 'saas-mode');
  document.getElementById('ws-app-content').classList.remove('visible');
  document.body.style.overflow = '';
  history.pushState({page:'marketplace'},'',window.location.pathname+window.location.search);
  setTimeout(() => window.scrollTo({top:savedScrollY,behavior:'instant'}), 50);
}
function refreshCharts() {
  if (typeof Chart === 'undefined') return;

  Object.values(Chart.instances || {}).forEach(chart => {
    try {
      chart.resize();
      chart.update();
    } catch (e) {
      console.log(e);
    }
  });
}
function switchScreen(index, name, el) {
  // Update sidebar active state
  document.querySelectorAll('#ws-screens-list .ws-nav-item')
    .forEach(s => s.classList.remove('ws-active'));

  if (el) el.classList.add('ws-active');

  const titleEl = document.getElementById('ws-screen-label');
  if (titleEl) titleEl.textContent = name;

  renderScreenInline(index, name);

  const area = document.getElementById('ws-content-area');
  if (area) area.scrollTop = 0;

  // Force charts to redraw after screen render
  setTimeout(() => {
    refreshCharts();
  }, 200);

  // Update routing URL
  if (currentTemplateName) {
    const templateId = slugify(currentTemplateName);
    const screenId = slugify(name);
    history.pushState({ templateId, screenId }, '', `/workspace/${templateId}/${screenId}`);
  }
}
function openScreen(index, name, el) { switchScreen(index, name, el); }
window.addEventListener('popstate', e => {
  if(!e.state) return;
  if(e.state.page==='screen') { /* handled */ }
  else if(e.state.page==='workspace') {
    document.getElementById('screen-page').classList.remove('visible');
    _showWorkspace(e.state.name, e.state.meta);
  } else {
    document.getElementById('screen-page').classList.remove('visible');
    const ws = document.getElementById('workspace-page');
    if(ws.classList.contains('visible')) {
      ws.classList.remove('visible', 'saas-mode');
      document.getElementById('ws-app-content').classList.remove('visible');
      document.body.style.overflow = '';
      setTimeout(() => window.scrollTo({top:savedScrollY,behavior:'instant'}), 50);
    }
  }
});

