function renderSPForecast(c) {
  const months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  const actuals = [42,55,48,62,70,58,75,82,79,88,null,null];
  const forecast = [null,null,null,null,null,null,null,null,null,88,96,104];
  return `
    <div style="padding:4px 0">
      <div style="display:grid;grid-template-columns:repeat(4,1fr);gap:14px;margin-bottom:20px">
        ${[['Q4 Forecast','$288K','Based on pipeline velocity','#F97316'],
           ['YTD Revenue','$483K','88% of annual target','#16A34A'],
           ['Goal Progress','88%','$52K remaining to target','#F59E0B'],
           ['Confidence','84%','High accuracy model','#3B82F6']].map(([l,v,s,col]) => `
          <div style="background:#fff;border:1.5px solid #E3E8EE;border-radius:16px;padding:18px">
            <div style="font-size:11px;font-weight:700;color:#697386;text-transform:uppercase;letter-spacing:0.7px;margin-bottom:6px">${l}</div>
            <div style="font-size:26px;font-weight:800;color:${col}">${v}</div>
            <div style="font-size:12px;color:#697386;margin-top:4px">${s}</div>
          </div>
        `).join('')}
      </div>
      <!-- Forecast Chart -->
      <div style="background:#fff;border:1.5px solid #E3E8EE;border-radius:16px;padding:20px;margin-bottom:14px">
        <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:16px">
          <div style="font-size:14px;font-weight:800;color:#0A2540">Revenue Forecast 2024</div>
          <div style="display:flex;gap:16px">
            <div style="display:flex;align-items:center;gap:6px"><div style="width:12px;height:3px;background:${c};border-radius:2px"></div><span style="font-size:11px;color:#697386">Actual</span></div>
            <div style="display:flex;align-items:center;gap:6px"><div style="width:12px;height:3px;background:#CBD5E1;border-radius:2px;border:1px dashed #94A3B8"></div><span style="font-size:11px;color:#697386">Forecast</span></div>
          </div>
        </div>
        <div style="height:140px;display:flex;align-items:flex-end;gap:6px">
          ${months.map((m,i) => {
            const h = actuals[i] ? Math.round((actuals[i]/104)*100) : Math.round((forecast[i]/104)*100);
            const isFore = forecast[i] && !actuals[i];
            return `<div style="flex:1;display:flex;flex-direction:column;align-items:center;gap:4px;height:100%">
              <div style="width:100%;height:${h}%;border-radius:5px 5px 0 0;background:${isFore?'repeating-linear-gradient(45deg,#CBD5E1,#CBD5E1 3px,#F1F5F9 3px,#F1F5F9 6px)':'linear-gradient(180deg,'+c+',#FB923C)'}"></div>
              <div style="font-size:9px;color:#697386">${m}</div>
            </div>`;
          }).join('')}
        </div>
      </div>
      <!-- Monthly Predictions + Goal Progress -->
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:14px">
        <div style="background:#fff;border:1.5px solid #E3E8EE;border-radius:16px;padding:20px">
          <div style="font-size:14px;font-weight:800;color:#0A2540;margin-bottom:14px">Monthly Predictions (Q4)</div>
          ${[['October','$88K','Completed','#16A34A',100],
             ['November','$96K','On track','#F97316',72],
             ['December','$104K','Forecasted','#3B82F6',48]].map(([mo,v,st,col,p]) => `
            <div style="padding:12px 0;border-bottom:1px solid #F8FAFC">
              <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:6px">
                <span style="font-size:13px;font-weight:600;color:#0A2540">${mo}</span>
                <span style="font-size:14px;font-weight:800;color:${col}">${v}</span>
              </div>
              <div style="height:6px;background:#F1F5F9;border-radius:3px;overflow:hidden">
                <div style="height:100%;width:${p}%;background:${col};border-radius:3px"></div>
              </div>
              <div style="font-size:11px;color:#697386;margin-top:4px">${st} · ${p}%</div>
            </div>
          `).join('')}
        </div>
        <div style="background:#fff;border:1.5px solid #E3E8EE;border-radius:16px;padding:20px">
          <div style="font-size:14px;font-weight:800;color:#0A2540;margin-bottom:14px">Sales Trend Analytics</div>
          ${[['Lead-to-Deal Conv.','18.4%','↑ +2.1%','#16A34A'],
             ['Sales Cycle Length','21 days','↓ -3 days','#3B82F6'],
             ['Avg Follow-ups','4.2','→ Stable','#F97316'],
             ['Proposal Accept Rate','62%','↑ +6%','#8B5CF6']].map(([l,v,chg,col]) => `
            <div style="display:flex;justify-content:space-between;align-items:center;padding:10px 0;border-bottom:1px solid #F8FAFC">
              <span style="font-size:12px;color:#425466">${l}</span>
              <div style="text-align:right"><div style="font-size:14px;font-weight:700;color:#0A2540">${v}</div><div style="font-size:11px;color:${col};font-weight:600">${chg}</div></div>
            </div>
          `).join('')}
        </div>
      </div>
    </div>
  `;
}

