              `).join('')}
            </div>
            <button style="margin-top:14px;padding:10px 24px;background:linear-gradient(135deg,${c},#EA580C);color:#fff;border:none;border-radius:10px;font-size:13px;font-weight:700;cursor:pointer">Save Preferences</button>
          </div>
        </div>
      </div>
    </div>
  `;
