function renderPanel(title, html, c) {
  return `
    <div style="background:#fff;border:1px solid #E3E8EE;border-radius:24px;padding:24px;margin-bottom:18px">
      <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:18px">
        <div>
          <div style="font-size:16px;font-weight:800;color:#0F172A">${title}</div>
          <div style="font-size:12px;color:#475569;margin-top:4px">Updated just now</div>
        </div>
        <div style="padding:8px 16px;background:linear-gradient(135deg,${c},#fff);border-radius:14px;color:${c};font-weight:700;font-size:12px">Live</div>
      </div>
      ${html}
    </div>
  `;
}
function renderMetricRow(label,value,sub) {
  return `
    <div style="display:flex;justify-content:space-between;align-items:center;padding:12px 0;border-bottom:1px solid #F1F5F9">
      <div style="font-size:12px;color:#475569">${label}</div>
      <div style="text-align:right">
        <div style="font-size:16px;font-weight:700;color:#0F172A">${value}</div>
        <div style="font-size:11px;color:#94A3B8">${sub}</div>
      </div>
    </div>
  `;
}
function renderProgressDot(label,value,percent,c) {
  return `
    <div style="background:#F8FAFC;border-radius:18px;padding:18px;display:flex;align-items:center;gap:14px">
      <div style="width:48px;height:48px;border-radius:50%;background:linear-gradient(135deg,${c}22,${c});display:flex;align-items:center;justify-content:center;font-weight:800;color:${c}">${percent}%</div>
      <div>
        <div style="font-size:12px;color:#475569">${label}</div>
        <div style="font-size:16px;font-weight:700;color:#0F172A">${value}</div>
      </div>
    </div>
  `;
}

