function getSaaSScreenHtml(index) {
  const c = getColor('SaaS Analytics Dashboard');
  const renderers = [
    renderSaaSExecutive, renderSaaSRevenueAnalytics, renderSaaSAcquisitionAnalytics,
    renderSaaSRetention, renderSaaSProductAnalytics, renderSaaSCustomerHealth,
    renderSaaSSubscriptionAnalytics, renderSaaSForecasting, renderSaaSAlerts,
    renderSaaSReports, renderSaaSAIInsights, renderSaaSAdministration
  ];
  return renderers[index] ? renderers[index](c) : renderers[0](c);
}

function saasNavItem(index, label, iconPath, badge, badgeClass, activeIndex) {
  const active = index === activeIndex ? ' active' : '';
  const badgeHtml = badge ? `<span class="saas-nav-badge${badgeClass ? ' ' + badgeClass : ''}">${badge}</span>` : '';
  return `<div class="saas-nav-item${active}" data-saas-idx="${index}" onclick="switchSaaSScreen(${index}, this)">
    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">${iconPath}</svg>
    ${label}${badgeHtml}
  </div>`;
}

