function bindSaaSAppInteractions() {
  const app = document.getElementById('saas-app');
  if (!app || app.dataset.clickBound) return;
  app.dataset.clickBound = '1';
  app.addEventListener('click', function(e) {
    const el = e.target.closest('[onclick]');
    if (!el || !app.contains(el)) return;
    const code = el.getAttribute('onclick');
    if (!code) return;
    e.preventDefault();
    e.stopPropagation();
    try { new Function(code).call(el); } catch (err) { console.error('SaaS click:', code, err); }
  }, true);
}

function afterSaaSScreenRender() {
  bindSaaSAppInteractions();
  requestAnimationFrame(() => {
    requestAnimationFrame(() => {
      try { initSaaSCharts(); } catch (err) { console.error('SaaS chart init:', err); }
      if (document.getElementById('cohort-body')) buildCohort();
      if (document.getElementById('health-list')) buildHealthList();
      if (document.getElementById('user-list')) buildUserList();
      if (document.getElementById('alerts-list')) buildAlerts();
      if (document.getElementById('ai-insights-list')) buildAIInsights();
      setTimeout(() => { if (typeof refreshCharts === 'function') refreshCharts(); }, 150);
      const searchBox = document.getElementById('saas-global-search');
      if (searchBox && !searchBox.dataset.bound) {
        searchBox.dataset.bound = '1';
        searchBox.addEventListener('keydown', e => {
          if (e.key === 'Enter' && e.target.value.trim()) {
            toast('Searching: ' + e.target.value.trim(), 'info');
            e.target.value = '';
          }
        });
      }
    });
  });
}

function switchSaaSScreen(index, el) {
  document.querySelectorAll('#saas-app .saas-nav-item').forEach(n => n.classList.remove('active'));
  if (el) el.classList.add('active');
  const meta = SAAS_SCREEN_META[index] || SAAS_SCREEN_META[0];
  const titleEl = document.getElementById('saas-topbar-title');
  const subEl = document.getElementById('saas-topbar-sub');
  if (titleEl) titleEl.textContent = meta.title;
  if (subEl) subEl.textContent = meta.sub;
  const content = document.getElementById('saas-content-area');
  if (content) {
    content.innerHTML = getSaaSScreenHtml(index);
    content.scrollTop = 0;
  }
  const screenLabel = document.getElementById('ws-screen-label');
  if (screenLabel) screenLabel.textContent = meta.title;
  afterSaaSScreenRender();
}

