function renderSATickets(c) {
  const tickets = [
    {id:'#4821',title:'Payment not processed on checkout',customer:'Ananya K.',channel:'Chat',priority:'Critical',status:'Open',assigned:'Priya S.',age:'12m'},
    {id:'#4820',title:'Can\'t reset password — email not arriving',customer:'Suresh V.',channel:'Email',priority:'High',status:'In Progress',assigned:'AI Agent',age:'28m'},
    {id:'#4819',title:'API timeout errors at peak load',customer:'Rohit B.',channel:'Email',priority:'Critical',status:'Open',assigned:'Arjun M.',age:'1h'},
    {id:'#4818',title:'Data export returning empty CSV',customer:'Kavya L.',channel:'Chat',priority:'Medium',status:'Pending',assigned:'Unassigned',age:'2h'},
    {id:'#4817',title:'Billing address update not saving',customer:'Deepa N.',channel:'Portal',priority:'High',status:'In Progress',assigned:'AI Agent',age:'2h'},
    {id:'#4816',title:'Feature request: bulk actions for tickets',customer:'Meera R.',channel:'Email',priority:'Low',status:'Open',assigned:'Unassigned',age:'4h'},
  ];
  const priBg={Critical:'#FEE2E2',High:'#FEF3C7',Medium:'#EFF6FF',Low:'#F5F5F5'};
  const priCol={Critical:'#DC2626',High:'#D97706',Medium:'#2563EB',Low:'#888'};
  const statBg={'Open':'#E8E7FF','In Progress':'#FEF3C7','Pending':'#FEE2E2','Resolved':'#DCFCE7'};
  const statCol={'Open':c,'In Progress':'#D97706','Pending':'#DC2626','Resolved':'#16A34A'};
  return `
    <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:18px">
      <div>
        <div style="font-size:20px;font-weight:800;color:var(--text);letter-spacing:-0.4px">Tickets</div>
        <div style="font-size:13px;color:var(--text-3);margin-top:3px">284 open · <span style="color:#DC2626;font-weight:600">12 critical</span></div>
      </div>
      <div style="display:flex;gap:8px">
        <div style="display:flex;gap:4px;background:#fff;border:1.5px solid var(--border);border-radius:9px;padding:4px 6px">
          ${['All','Open','In Progress','Pending','Resolved'].map((t,i)=>`<div style="padding:5px 12px;border-radius:7px;font-size:12px;font-weight:600;cursor:pointer;${i===0?`background:${c};color:#fff`:'color:var(--text-3)'}">${t}</div>`).join('')}
        </div>
        <button style="padding:8px 16px;background:${c};color:#fff;border:none;border-radius:9px;font-size:13px;font-weight:600;cursor:pointer;font-family:var(--font)">+ New Ticket</button>
      </div>
    </div>
    <div style="display:grid;grid-template-columns:repeat(4,1fr);gap:12px;margin-bottom:18px">
      ${[['284','Open',c,'#E8E7FF'],['12','Critical','#DC2626','#FEE2E2'],['48','In Progress','#D97706','#FEF3C7'],['1,024','Resolved Today','#16A34A','#DCFCE7']].map(([v,l,col,bg])=>`
        <div style="background:${bg};border:1.5px solid ${col}30;border-radius:12px;padding:14px 16px">
          <div style="font-size:22px;font-weight:800;color:${col};letter-spacing:-0.5px">${v}</div>
          <div style="font-size:12px;color:var(--text-3);margin-top:3px">${l}</div>
        </div>
      `).join('')}
    </div>
    <div style="background:#fff;border:1.5px solid var(--border);border-radius:14px;overflow:hidden;margin-bottom:16px">
      <div style="padding:14px 18px;border-bottom:1px solid var(--border);display:flex;align-items:center;justify-content:space-between">
        <span style="font-size:13.5px;font-weight:700;color:var(--text)">Ticket Queue</span>
        <div style="display:flex;gap:6px">
          <div style="padding:5px 12px;background:var(--bg);border:1px solid var(--border);border-radius:7px;font-size:12px;cursor:pointer">Sort: Newest</div>
          <div style="padding:5px 12px;background:var(--bg);border:1px solid var(--border);border-radius:7px;font-size:12px;cursor:pointer">Assign All</div>
        </div>
      </div>
      <div class="ws-table-wrap">
        <table class="ws-table">
          <thead><tr><th>ID</th><th>Issue</th><th>Customer</th><th>Channel</th><th>Priority</th><th>Assigned</th><th>Age</th><th>Status</th></tr></thead>
          <tbody>
            ${tickets.map(t=>`
              <tr style="cursor:pointer" onmouseover="this.style.background='var(--bg)'" onmouseout="this.style.background=''">
                <td style="font-weight:700;color:${c}">${t.id}</td>
                <td style="font-weight:600;max-width:180px">${t.title}</td>
                <td>${t.customer}</td>
                <td><span style="background:var(--bg);border:1px solid var(--border);border-radius:5px;padding:2px 8px;font-size:11px">${t.channel}</span></td>
                <td><span class="ws-badge" style="background:${priBg[t.priority]};color:${priCol[t.priority]}">${t.priority}</span></td>
                <td style="font-size:12.5px">${t.assigned}</td>
                <td style="font-size:12px;color:var(--text-4)">${t.age}</td>
                <td><span class="ws-badge" style="background:${statBg[t.status]};color:${statCol[t.status]}">${t.status}</span></td>
              </tr>
            `).join('')}
          </tbody>
        </table>
      </div>
    </div>
  `;
}

