function renderWCDashboard(c) {
  // Sparkline generator
  function spark(vals, col, h) {
    const max = Math.max(...vals), min = Math.min(...vals);
    const range = max - min || 1;
    const w = 80, ht = h || 28;
    const pts = vals.map((v,i) => `${i*(w/(vals.length-1))},${ht - ((v-min)/range)*(ht-4)+2}`).join(' ');
    return `<svg width="${w}" height="${ht}" viewBox="0 0 ${w} ${ht}" style="display:block"><polyline points="${pts}" fill="none" stroke="${col}" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/></svg>`;
  }
  const workflows = [
    {id:'wf1', name:'Email Automation', icon:'✉️', status:'Active', pct:78, executions:'1,240', color:'#635BFF', spark:[30,45,38,60,55,72,78], badge:'bg:#E8E7FF;color:#635BFF'},
    {id:'wf2', name:'AI Content Process', icon:'🤖', status:'Active', pct:91, executions:'3,812', color:c, spark:[50,65,80,75,88,84,91], badge:'bg:#F3E8FF;color:#9333EA'},
    {id:'wf3', name:'Database Sync', icon:'🗄️', status:'Active', pct:64, executions:'984', color:'#00D4B1', spark:[40,50,44,58,52,60,64], badge:'bg:#E0FBF4;color:#00A37A'},
    {id:'wf4', name:'Customer Support Flow', icon:'💬', status:'Active', pct:85, executions:'2,107', color:'#FF5996', spark:[60,70,65,78,72,82,85], badge:'bg:#FFE3EE;color:#FF5996'},
  ];
  return `
  <div style="font-family:var(--font);padding:4px 0">
    <!-- Top Bar -->
    <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:22px;gap:12px;flex-wrap:wrap">
      <div>
        <div style="font-size:21px;font-weight:800;color:var(--text);letter-spacing:-0.5px">Workflow Studio</div>
        <div style="font-size:13px;color:var(--text-3);margin-top:3px">AI-powered workspace · 4 active workflows</div>
      </div>
      <div style="display:flex;gap:8px;flex-wrap:wrap">
        <div style="display:flex;align-items:center;gap:6px;padding:7px 14px;background:var(--cream);border:1.5px solid var(--border);border-radius:10px">
          <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="var(--text-4)" stroke-width="2" stroke-linecap="round"><circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/></svg>
          <input placeholder="Search workflows…" style="border:none;background:none;font-family:var(--font);font-size:13px;color:var(--text);outline:none;width:160px" id="wf-search"/>
        </div>
        <button onclick="showOaToast('Workflow saved ✓')" style="display:flex;align-items:center;gap:6px;padding:8px 16px;background:#fff;border:1.5px solid var(--border);border-radius:10px;font-size:13px;font-weight:600;color:var(--text-2);cursor:pointer;font-family:var(--font)">
          <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round"><path d="M19 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11l5 5v11a2 2 0 0 1-2 2z"/><polyline points="17 21 17 13 7 13 7 21"/><polyline points="7 3 7 8 15 8"/></svg>
          Save
        </button>
        <button onclick="showOaToast('Running workflows…')" style="display:flex;align-items:center;gap:6px;padding:8px 16px;background:#fff;border:1.5px solid var(--border);border-radius:10px;font-size:13px;font-weight:600;color:var(--text-2);cursor:pointer;font-family:var(--font)">
          <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round"><polygon points="5 3 19 12 5 21 5 3"/></svg>
          Run
        </button>
        <button onclick="showOaToast('Workflow published! 🚀')" style="display:flex;align-items:center;gap:6px;padding:8px 16px;background:linear-gradient(135deg,${c},#FF5996);color:#fff;border:none;border-radius:10px;font-size:13px;font-weight:700;cursor:pointer;font-family:var(--font)">
          <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="#fff" stroke-width="2.5" stroke-linecap="round"><polyline points="22 2 11 13"/><polygon points="22 2 15 22 11 13 2 9 22 2"/></svg>
          Publish
        </button>
      </div>
    </div>

    <!-- Main Workspace Layout -->
    <div style="display:grid;grid-template-columns:180px 1fr 220px;gap:14px;align-items:start">

      <!-- LEFT SIDEBAR -->
      <div style="background:#fff;border:1.5px solid var(--border);border-radius:16px;padding:14px;display:flex;flex-direction:column;gap:4px">
        <div style="font-size:10.5px;font-weight:700;color:var(--text-4);text-transform:uppercase;letter-spacing:0.8px;padding:4px 8px;margin-bottom:4px">Workspace</div>
        ${[
          ['📋','Templates','openWorkspace(\'AI Workflow Copilot\',\'\')'],
          ['⚡','Triggers','switchScreen(2,\'Trigger Center\',document.querySelector(\'#ws-screens-list .ws-nav-item:nth-child(3)\'))'],
          ['🔗','Integrations','showOaToast(\'Integrations panel opened\')'],
          ['▶️','Actions','showOaToast(\'Actions library opened\')'],
          ['🤖','AI Tools','showOaToast(\'AI Tools panel opened\')'],
        ].map(([ico,lbl,fn])=>`
          <button onclick="${fn}" style="display:flex;align-items:center;gap:10px;padding:10px 12px;background:none;border:none;border-radius:10px;font-size:13px;font-weight:600;color:var(--text-2);cursor:pointer;font-family:var(--font);text-align:left;width:100%;transition:background 0.15s" onmouseover="this.style.background='var(--lilac)';this.style.color='var(--indigo)'" onmouseout="this.style.background='none';this.style.color='var(--text-2)'">
            <span style="font-size:15px">${ico}</span>${lbl}
          </button>
        `).join('')}
        <div style="border-top:1px solid var(--border);margin:8px 0;padding-top:8px">
          <div style="font-size:10.5px;font-weight:700;color:var(--text-4);text-transform:uppercase;letter-spacing:0.8px;padding:4px 8px;margin-bottom:4px">Recent</div>
          ${['Email Blast','Lead Score','Onboarding'].map(n=>`
            <div style="padding:7px 12px;font-size:12px;color:var(--text-3);cursor:pointer;border-radius:8px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis" onmouseover="this.style.background='var(--bg)'" onmouseout="this.style.background='none'">${n}</div>
          `).join('')}
        </div>
      </div>

      <!-- CENTER WORKSPACE -->
      <div style="display:flex;flex-direction:column;gap:14px">
        <!-- Workflow Cards Grid -->
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:14px" id="wf-cards-grid">
          ${workflows.map(wf=>`
            <div id="card-${wf.id}" style="background:#fff;border:1.5px solid var(--border);border-radius:18px;padding:18px 20px;cursor:pointer;transition:all 0.2s;position:relative;overflow:hidden" onmouseover="this.style.borderColor='${wf.color}';this.style.boxShadow='0 8px 32px ${wf.color}22';this.style.transform='translateY(-2px)'" onmouseout="this.style.borderColor='var(--border)';this.style.boxShadow='none';this.style.transform='none'">
              <!-- Top row -->
              <div style="display:flex;align-items:flex-start;justify-content:space-between;margin-bottom:12px">
                <div style="display:flex;align-items:center;gap:10px">
                  <div style="width:38px;height:38px;border-radius:11px;background:${wf.color}18;display:flex;align-items:center;justify-content:center;font-size:18px">${wf.icon}</div>
                  <div>
                    <div style="font-size:14px;font-weight:700;color:var(--text)">${wf.name}</div>
                    <div style="font-size:11px;color:var(--text-4);margin-top:1px">${wf.executions} executions</div>
                  </div>
                </div>
                <span style="padding:3px 10px;border-radius:20px;font-size:11px;font-weight:700;background:${wf.badge.split(';')[0].replace('bg:','')};color:${wf.badge.split(';')[1].replace('color:','')}">${wf.status}</span>
              </div>
              <!-- Progress -->
              <div style="margin-bottom:10px">
                <div style="display:flex;justify-content:space-between;margin-bottom:5px">
                  <span style="font-size:11.5px;color:var(--text-4);font-weight:600">Progress</span>
                  <span style="font-size:11.5px;font-weight:700;color:${wf.color}">${wf.pct}%</span>
                </div>
                <div style="height:5px;background:var(--cream2);border-radius:3px;overflow:hidden"><div style="height:100%;width:${wf.pct}%;background:linear-gradient(90deg,${wf.color},${wf.color}aa);border-radius:3px;transition:width 0.6s"></div></div>
              </div>
              <!-- Spark + actions -->
              <div style="display:flex;align-items:center;justify-content:space-between">
                ${spark(wf.spark, wf.color, 28)}
                <div style="display:flex;gap:6px">
                  <button onclick="event.stopPropagation();showOaToast('${wf.name} edited')" style="padding:5px 10px;background:var(--cream);border:1.5px solid var(--border);border-radius:8px;font-size:11px;font-weight:600;color:var(--text-3);cursor:pointer;font-family:var(--font)">Edit</button>
                  <button onclick="event.stopPropagation();showOaToast('${wf.name} running…')" style="padding:5px 10px;background:${wf.color};border:none;border-radius:8px;font-size:11px;font-weight:700;color:#fff;cursor:pointer;font-family:var(--font)">▶ Run</button>
                </div>
              </div>
            </div>
          `).join('')}
        </div>

        <!-- Add New Workflow CTA -->
        <button onclick="showOaToast('New workflow created!')" style="display:flex;align-items:center;justify-content:center;gap:8px;padding:14px;background:#fff;border:2px dashed var(--border);border-radius:16px;font-size:14px;font-weight:600;color:var(--text-3);cursor:pointer;font-family:var(--font);width:100%;transition:all 0.2s" onmouseover="this.style.borderColor='${c}';this.style.color='${c}';this.style.background='${c}08'" onmouseout="this.style.borderColor='var(--border)';this.style.color='var(--text-3)';this.style.background='#fff'">
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round"><line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/></svg>
          Add New Workflow
        </button>

        <!-- Stats Row -->
        <div style="display:grid;grid-template-columns:repeat(3,1fr);gap:10px">
          ${[
            {label:'Active Flows',val:'4',trend:'+1 this week',col:'#00D4B1'},
            {label:'Total Executions',val:'8,143',trend:'+18% vs yesterday',col:c},
            {label:'Success Rate',val:'98.7%',trend:'↑ 0.4%',col:'#635BFF'},
          ].map(k=>`
            <div style="background:#fff;border:1.5px solid var(--border);border-radius:14px;padding:14px 16px">
              <div style="font-size:11px;font-weight:700;color:var(--text-4);text-transform:uppercase;letter-spacing:0.5px;margin-bottom:6px">${k.label}</div>
              <div style="font-size:24px;font-weight:800;color:var(--text);letter-spacing:-0.8px;margin-bottom:3px">${k.val}</div>
              <div style="font-size:11.5px;color:${k.col};font-weight:600">${k.trend}</div>
            </div>
          `).join('')}
        </div>
      </div>

      <!-- RIGHT SIDEBAR: AI Assistant -->
      <div style="background:#fff;border:1.5px solid var(--border);border-radius:16px;overflow:hidden;display:flex;flex-direction:column">
        <!-- Header -->
        <div style="padding:14px 16px;background:linear-gradient(135deg,${c}15,#FF599615);border-bottom:1px solid var(--border)">
          <div style="display:flex;align-items:center;gap:8px">
            <div style="width:28px;height:28px;border-radius:8px;background:linear-gradient(135deg,${c},#FF5996);display:flex;align-items:center;justify-content:center">
              <svg width="13" height="13" viewBox="0 0 24 24" fill="white"><circle cx="12" cy="12" r="3"/><path d="M19.07 4.93a10 10 0 0 1 0 14.14M4.93 4.93a10 10 0 0 0 0 14.14" stroke="white" fill="none" stroke-width="2"/></svg>
            </div>
            <div>
              <div style="font-size:13px;font-weight:700;color:var(--text)">AI Assistant</div>
              <div style="font-size:10.5px;color:var(--text-4)">● Online</div>
            </div>
          </div>
        </div>

        <!-- Suggestions -->
        <div style="padding:12px 14px;border-bottom:1px solid var(--border)">
          <div style="font-size:10.5px;font-weight:700;color:var(--text-4);text-transform:uppercase;letter-spacing:0.7px;margin-bottom:8px">💡 Suggestions</div>
          ${['Optimize email timing','Add retry logic','Enable A/B testing'].map(s=>`
            <div onclick="showOaToast('Applied: ${s}')" style="padding:8px 10px;background:var(--cream);border-radius:9px;font-size:12px;color:var(--text-2);cursor:pointer;margin-bottom:5px;font-weight:500;transition:background 0.15s" onmouseover="this.style.background='var(--lilac)'" onmouseout="this.style.background='var(--cream)'">${s} <span style="color:${c}">→</span></div>
          `).join('')}
        </div>

        <!-- Recent Activity -->
        <div style="padding:12px 14px;border-bottom:1px solid var(--border)">
          <div style="font-size:10.5px;font-weight:700;color:var(--text-4);text-transform:uppercase;letter-spacing:0.7px;margin-bottom:8px">🕐 Recent Activity</div>
          ${[['Email Automation ran','2m ago','#00D4B1'],['AI model updated','11m ago',c],['DB sync completed','1h ago','#635BFF']].map(([t,d,col])=>`
            <div style="display:flex;align-items:center;gap:8px;padding:6px 0;border-bottom:1px solid var(--border-2)">
              <div style="width:6px;height:6px;border-radius:50%;background:${col};flex-shrink:0"></div>
              <div style="flex:1;font-size:11.5px;color:var(--text-2);font-weight:500">${t}</div>
              <div style="font-size:10px;color:var(--text-4)">${d}</div>
            </div>
          `).join('')}
        </div>

        <!-- Smart Tips -->
        <div style="padding:12px 14px;border-bottom:1px solid var(--border)">
          <div style="font-size:10.5px;font-weight:700;color:var(--text-4);text-transform:uppercase;letter-spacing:0.7px;margin-bottom:8px">🎯 Smart Tips</div>
          <div style="padding:10px 12px;background:${c}10;border:1px solid ${c}30;border-radius:10px;font-size:12px;color:var(--text-2);line-height:1.5">Customer Support Flow has a 12% higher success rate when triggered between 9–11am.</div>
        </div>

        <!-- Quick Actions -->
        <div style="padding:12px 14px">
          <div style="font-size:10.5px;font-weight:700;color:var(--text-4);text-transform:uppercase;letter-spacing:0.7px;margin-bottom:8px">⚡ Quick Actions</div>
          <div style="display:grid;grid-template-columns:1fr 1fr;gap:6px">
            ${[['Export','showOaToast(\'Exporting workflows…\')'],['Duplicate','showOaToast(\'Workflow duplicated\')'],['Schedule','showOaToast(\'Scheduler opened\')'],['Analyze','showOaToast(\'Running analysis…\')']].map(([l,fn])=>`
              <button onclick="${fn}" style="padding:7px 6px;background:var(--cream);border:1.5px solid var(--border);border-radius:9px;font-size:11.5px;font-weight:600;color:var(--text-2);cursor:pointer;font-family:var(--font);transition:all 0.15s" onmouseover="this.style.borderColor='${c}';this.style.color='${c}'" onmouseout="this.style.borderColor='var(--border)';this.style.color='var(--text-2)'">${l}</button>
            `).join('')}
          </div>
        </div>
      </div>

    </div>
  </div>
  `;
}

function renderWCAutomationFlow(c) {
  const stages = [
    {name:'Input Sources',color:'#00D4B1',items:['Webhook','Scheduler','API Trigger','Form Submit'],count:4},
    {name:'Processing',color:c,items:['AI Parse','Data Map','Transform','Validate'],count:4},
    {name:'Decision',color:'#F97316',items:['Condition A','Condition B','Route Logic'],count:3},
    {name:'Actions',color:'#635BFF',items:['Send Email','Update DB','Notify Slack','API Call'],count:4},
    {name:'Output',color:'#FF5996',items:['Dashboard','Report','Webhook Out'],count:3},
  ];
  return `
    <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:20px">
      <div>
        <div style="font-size:20px;font-weight:800;color:var(--text);letter-spacing:-0.4px">Automation Flow</div>
        <div style="font-size:13px;color:var(--text-3);margin-top:3px">Connected pipeline · 18 automation stages running</div>
      </div>
      <button style="padding:8px 16px;background:${c};color:#fff;border:none;border-radius:9px;font-size:13px;font-weight:600;cursor:pointer;font-family:var(--font)">+ Add Stage</button>
    </div>
    <div style="background:#fff;border:1.5px solid var(--border);border-radius:16px;padding:24px;margin-bottom:16px;overflow-x:auto">
      <div style="display:flex;align-items:center;gap:0;min-width:700px">
        ${stages.map((s,i)=>`
          <div style="flex:1;display:flex;flex-direction:column;align-items:center;position:relative">
            <div style="width:100%;background:${s.color}12;border:2px solid ${s.color}40;border-radius:14px;padding:14px;margin:0 6px;position:relative">
              <div style="font-size:12px;font-weight:800;color:${s.color};text-transform:uppercase;letter-spacing:0.5px;margin-bottom:10px;text-align:center">${s.name}</div>
              ${s.items.map(item=>`
                <div style="background:#fff;border:1px solid ${s.color}30;border-radius:8px;padding:7px 10px;margin-bottom:6px;font-size:12px;font-weight:600;color:var(--text-2);text-align:center;cursor:pointer" onmouseover="this.style.background='${s.color}15'" onmouseout="this.style.background='#fff'">${item}</div>
              `).join('')}
              <div style="text-align:center;margin-top:8px;font-size:11px;color:${s.color};font-weight:700">${s.count} nodes</div>
            </div>
            ${i<stages.length-1?`<div style="position:absolute;right:-14px;top:50%;transform:translateY(-50%);z-index:2;font-size:18px;color:${s.color}">→</div>`:''}
          </div>
        `).join('')}
      </div>
    </div>
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:14px">
      <div style="background:#fff;border:1.5px solid var(--border);border-radius:14px;padding:20px">
        <div style="font-size:14px;font-weight:700;color:var(--text);margin-bottom:14px">Recent Runs</div>
        ${[
          {name:'Lead Enrichment Flow',status:'Success',time:'2m ago',col:'#00D4B1'},
          {name:'Invoice Automation',status:'Running',time:'Just now',col:c},
          {name:'Support Triage',status:'Success',time:'8m ago',col:'#00D4B1'},
          {name:'Data Sync Pipeline',status:'Failed',time:'15m ago',col:'#E5484D'},
          {name:'Onboarding Sequence',status:'Success',time:'22m ago',col:'#00D4B1'},
        ].map(r=>`
          <div style="display:flex;align-items:center;gap:10px;padding:9px 0;border-bottom:1px solid var(--border)">
            <div style="width:8px;height:8px;border-radius:50%;background:${r.col};flex-shrink:0"></div>
            <div style="flex:1;font-size:13px;font-weight:600;color:var(--text)">${r.name}</div>
            <div style="font-size:11px;color:var(--text-4)">${r.time}</div>
            <div style="padding:2px 10px;background:${r.col}20;color:${r.col};border-radius:12px;font-size:11px;font-weight:700">${r.status}</div>
          </div>
        `).join('')}
      </div>
      <div style="background:#fff;border:1.5px solid var(--border);border-radius:14px;padding:20px">
        <div style="font-size:14px;font-weight:700;color:var(--text);margin-bottom:14px">Flow Performance</div>
        <div style="display:flex;align-items:flex-end;gap:5px;height:120px;margin-bottom:10px">
          ${['Mon','Tue','Wed','Thu','Fri','Sat','Sun'].map((d,i)=>{const h=[60,75,55,90,80,45,95][i];return`<div style="flex:1;display:flex;flex-direction:column;align-items:center;gap:4px;height:100%"><div style="width:100%;border-radius:5px 5px 0 0;background:${i===6?c:c+'60'};height:${h}%"></div><div style="font-size:10px;color:var(--text-4);font-weight:600">${d}</div></div>`;}).join('')}
        </div>
        <div style="font-size:12px;color:var(--text-4);text-align:center">Executions this week · avg 1,204/day</div>
      </div>
    </div>
  `;
}

