function renderWCSettings(c) {
  return `
    <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:20px">
      <div>
        <div style="font-size:20px;font-weight:800;color:var(--text);letter-spacing:-0.4px">Settings</div>
        <div style="font-size:13px;color:var(--text-3);margin-top:3px">Workflow engine, AI config & integrations</div>
      </div>
      <button style="padding:8px 16px;background:${c};color:#fff;border:none;border-radius:9px;font-size:13px;font-weight:600;cursor:pointer;font-family:var(--font)">Save Changes</button>
    </div>
    <div style="display:grid;grid-template-columns:200px 1fr;gap:16px">
      <div style="background:#fff;border:1.5px solid var(--border);border-radius:14px;padding:12px;display:flex;flex-direction:column;gap:2px;height:fit-content">
        ${[['General','active'],['AI Engine',''],['Integrations',''],['Notifications',''],['Security',''],['Billing',''],['API Keys','']].map(([l,a])=>`
          <div style="padding:9px 12px;border-radius:9px;font-size:13px;font-weight:${a?600:500};cursor:pointer;color:${a?c:'var(--text-2)'};background:${a?c+'10':'transparent'}">${l}</div>
        `).join('')}
      </div>
      <div style="display:flex;flex-direction:column;gap:14px">
        <div style="background:#fff;border:1.5px solid var(--border);border-radius:14px;padding:20px">
          <div style="font-size:14px;font-weight:700;color:var(--text);margin-bottom:14px">Workflow Engine</div>
          ${[
            ['Max concurrent flows','AI auto-scaling enabled',true],
            ['Error retry policy','Retry failed steps up to 3× with backoff',true],
            ['Flow versioning','Keep history of all flow versions',true],
            ['Debug mode','Log full execution trace for debugging',false],
            ['Sandbox testing','Test flows without triggering real actions',true],
          ].map(([l,d,on])=>`
            <div style="display:flex;align-items:center;justify-content:space-between;padding:12px 0;border-bottom:1px solid var(--border)">
              <div>
                <div style="font-size:13.5px;font-weight:600;color:var(--text)">${l}</div>
                <div style="font-size:12px;color:var(--text-4);margin-top:2px">${d}</div>
              </div>
              <div onclick="this.classList.toggle('tog-on');this.style.background=this.classList.contains('tog-on')?'${c}':'var(--border-2)';this.querySelector('div').style.left=this.classList.contains('tog-on')?'21px':'3px'" style="width:42px;height:24px;border-radius:12px;background:${on?c:'var(--border-2)'};cursor:pointer;position:relative;transition:background 0.2s;flex-shrink:0">
                <div style="position:absolute;top:3px;${on?'left:21px':'left:3px'};width:18px;height:18px;border-radius:50%;background:#fff;transition:left 0.2s;box-shadow:0 1px 4px rgba(0,0,0,0.2)"></div>
              </div>
            </div>
          `).join('')}
        </div>
        <div style="background:#fff;border:1.5px solid var(--border);border-radius:14px;padding:20px">
          <div style="font-size:14px;font-weight:700;color:var(--text);margin-bottom:14px">AI Model Config</div>
          <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:14px">
            ${[['AI Model','Claude Sonnet 4'],['Temperature','0.3 (precise)'],['Max tokens','4,096'],['AI Memory','Session + persistent']].map(([l,v])=>`
              <div>
                <div style="font-size:11px;font-weight:700;color:var(--text-4);margin-bottom:5px;text-transform:uppercase;letter-spacing:0.5px">${l}</div>
                <div style="padding:9px 12px;background:var(--bg);border:1.5px solid var(--border);border-radius:9px;font-size:13px;color:var(--text);font-weight:500">${v}</div>
              </div>
            `).join('')}
          </div>
        </div>
        <div style="background:#fff;border:1.5px solid var(--border);border-radius:14px;padding:20px">
          <div style="font-size:14px;font-weight:700;color:var(--text);margin-bottom:14px">Connected Integrations</div>
          ${[['Slack','Alerts + notifications','#635BFF','Connected'],['Stripe','Billing triggers','#00D4B1','Connected'],['HubSpot','CRM sync','#FF5996','Connected'],['Zapier','Flow export','#F59E0B','Not connected']].map(([name,desc,col,status])=>`
            <div style="display:flex;align-items:center;justify-content:space-between;padding:12px 0;border-bottom:1px solid var(--border)">
              <div style="display:flex;align-items:center;gap:10px">
                <div style="width:32px;height:32px;border-radius:9px;background:${col}20;display:flex;align-items:center;justify-content:center;font-size:14px;font-weight:800;color:${col}">${name[0]}</div>
                <div>
                  <div style="font-size:13px;font-weight:600;color:var(--text)">${name}</div>
                  <div style="font-size:12px;color:var(--text-4)">${desc}</div>
                </div>
              </div>
              <div style="padding:5px 14px;background:${col}15;color:${col};border-radius:8px;font-size:12px;font-weight:600;cursor:pointer">${status==='Connected'?'Configure':'Connect'}</div>
            </div>
          `).join('')}
        </div>
      </div>
    </div>
  `;
}

