// ─── AI Studio: Main (Dashboard) — already handled by renderAppContent, here as alias ───
// This function dispatches all AI Studio screens except index 0
function renderAIStudioScreen(index, screenName, c) {
  const aiScreens = {
    1: () => renderASPromptLab(c),
    2: () => renderASAIChat(c),
    3: () => renderASModels(c),
    4: () => renderASTraining(c),
    5: () => renderASDatasets(c),
    6: () => renderASWorkflows(c),
    7: () => renderASAnalytics(c),
    8: () => renderASIntegrations(c),
    9: () => renderASSettings(c),
  };
  if(aiScreens[index]) return aiScreens[index]();
  return renderGenericScreen(index, screenName, c, TEMPLATE_SCREENS['AI Studio']);
}

function kpi(label, val, c, bg, icon, trend, sub) {
  return `<div class="ws-kpi">
    <div class="ws-kpi-label">${label} <div class="ws-kpi-icon" style="background:${bg}"><svg viewBox="0 0 24 24" fill="none" stroke="${c}" stroke-width="2" stroke-linecap="round"><path d="${icon}"/></svg></div></div>
    <div class="ws-kpi-val">${val}</div>
    <div class="ws-kpi-trend ${trend}"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round"><polyline points="${trend==='up'?'23 6 13.5 15.5 8.5 10.5 1 18':'23 18 13.5 8.5 8.5 13.5 1 6'}"/><polyline points="${trend==='up'?'17 6 23 6 23 12':'17 18 23 18 23 12'}"/></svg> ${sub}</div>
  </div>`;
}

