// ═══ AI CHAT ═══
const aiResponses = {
  'change colors': '✨ Updated the color palette to a fresh gradient. All cards, buttons, and highlights now reflect the new theme.',
  'add new card': '🃏 Added a new KPI card "Weekly Goal Progress" to the dashboard grid.',
  'dark mode': '🌙 Switched to dark mode — all 10 screens now use the dark theme with your accent color.',
  'change layout': '📐 Switched to an asymmetric two-column layout for better data density.',
  'add chart': '📈 Added a live bar chart showing 30-day trends with your brand gradient.',
};
function sendChatMsg() {
  const input = document.getElementById('ws-chat-input');
  const msg = input.value.trim();
  if(!msg) return;
  addChatMsg(msg,'user');
  input.value = '';
  input.style.height = 'auto';
  const typing = document.createElement('div');
  typing.className = 'ws-chat-typing show';
  typing.innerHTML = '<div class="ws-typing-dot"></div><div class="ws-typing-dot"></div><div class="ws-typing-dot"></div>';
  document.getElementById('ws-chat-msgs').appendChild(typing);
  scrollChat();
  setTimeout(() => {
    typing.remove();
    const lc = msg.toLowerCase();
    const reply = aiResponses[lc] || `✅ Got it! Applied "${msg}" to your workspace. The changes are live in the preview.`;
    addChatMsg(reply,'ai');
  }, 1400);
}
function sendHint(el) {
  document.getElementById('ws-chat-input').value = el.textContent.trim();
  sendChatMsg();
}
function chatKeydown(e) {
  if(e.key==='Enter'&&!e.shiftKey){e.preventDefault();sendChatMsg();}
}
function addChatMsg(text,type) {
  const msgs = document.getElementById('ws-chat-msgs');
  const now = new Date().toLocaleTimeString('en',{hour:'2-digit',minute:'2-digit'});
  const el = document.createElement('div');
  el.className = `ws-msg ws-msg-${type}`;
  el.innerHTML = `<div class="ws-msg-bubble">${text}</div><div class="ws-msg-time">${now}</div>`;
  msgs.appendChild(el);
  scrollChat();
}
function scrollChat() {
  const msgs = document.getElementById('ws-chat-msgs');
  msgs.scrollTop = msgs.scrollHeight;
}
function wsNavClick(el,section) {
  document.querySelectorAll('.ws-nav-item').forEach(n => n.classList.remove('ws-active'));
  el.classList.add('ws-active');
}
function previewTemplate(name) { openWorkspace(name,''); }
function slugify(name) { return name.toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/^-|-$/g,''); }

